+    fn vacuum_extra_sqlite_master_entries(&self) -> Vec<crate::compat_persist::SqliteMasterEntry> {
+        self.build_sqlite_master_rows()
+            .into_iter()
+            .filter_map(|row| {
+                if row.len() < 5 {
+                    return None;
+                }
+                let entry_type = match &row[0] {
+                    SqliteValue::Text(text) => text.to_string(),
+                    _ => return None,
+                };
+                if entry_type.eq_ignore_ascii_case("table") || entry_type.eq_ignore_ascii_case("index")
+                {
+                    return None;
+                }
+                let name = match &row[1] {
+                    SqliteValue::Text(text) => text.to_string(),
+                    _ => return None,
+                };
+                let tbl_name = match &row[2] {
+                    SqliteValue::Text(text) => text.to_string(),
+                    _ => return None,
+                };
+                let root_page = match row.get(3) {
+                    Some(SqliteValue::Integer(n)) if *n >= 0 => u32::try_from(*n).ok()?,
+                    _ => return None,
+                };
+                let sql = match row.get(4) {
+                    Some(SqliteValue::Text(text)) => Some(text.to_string()),
+                    Some(SqliteValue::Null) => None,
+                    _ => return None,
+                };
+                Some((entry_type, name, tbl_name, root_page, sql))
+            })
+            .collect()
+    }
