+/// Returns `true` when a finalized program still needs an attached
+/// `MemDatabase` to preserve its current semantics.
+///
+/// This is intentionally conservative. It only returns `false` for programs
+/// that stay on storage cursors plus pure register/control-flow opcodes, which
+/// lets hot prepared table executions skip the `MemDatabase` handoff entirely.
+fn compute_requires_attached_memdb(ops: &[VdbeOp]) -> bool {
+    let mut storage_cursor_ids = HashSet::new();
+
+    for op in ops {
+        match op.opcode {
+            Opcode::OpenRead | Opcode::OpenWrite | Opcode::FusedOpenWriteLast => {
+                storage_cursor_ids.insert(op.p1);
+            }
+            Opcode::Close => {
+                storage_cursor_ids.remove(&op.p1);
+            }
+            Opcode::OpenEphemeral
+            | Opcode::OpenAutoindex
+            | Opcode::OpenPseudo
+            | Opcode::OpenDup
+            | Opcode::ReopenIdx
+            | Opcode::SorterOpen
+            | Opcode::CreateBtree
+            | Opcode::Clear
+            | Opcode::Destroy
+            | Opcode::Pagecount
+            | Opcode::Program
+            | Opcode::VBegin
+            | Opcode::VCreate
+            | Opcode::VDestroy
+            | Opcode::VOpen
+            | Opcode::VCheck
+            | Opcode::VInitIn
+            | Opcode::VFilter
+            | Opcode::VColumn
+            | Opcode::VNext
+            | Opcode::VRename
+            | Opcode::VUpdate => return true,
+            Opcode::Rewind
+            | Opcode::Last
+            | Opcode::Next
+            | Opcode::Prev
+            | Opcode::Column
+            | Opcode::Count
+            | Opcode::SeekLT
+            | Opcode::SeekLE
+            | Opcode::SeekGE
+            | Opcode::SeekGT
+            | Opcode::IfNoHope
+            | Opcode::NoConflict
+            | Opcode::NotFound
+            | Opcode::Found
+            | Opcode::SeekRowid
+            | Opcode::NotExists
+            | Opcode::Insert
+            | Opcode::Delete
+            | Opcode::RowData
+            | Opcode::Rowid
+            | Opcode::NullRow
+            | Opcode::IfNullRow
+            | Opcode::IfEmpty
+            | Opcode::IfSizeBetween
+            | Opcode::IdxInsert
+            | Opcode::IdxDelete
+            | Opcode::DeferredSeek
+            | Opcode::IdxRowid
+            | Opcode::FinishSeek
+            | Opcode::IdxLE
+            | Opcode::IdxGT
+            | Opcode::IdxLT
+            | Opcode::IdxGE
+            | Opcode::SetSnapshot
+            | Opcode::CountIndexEqRun
+            | Opcode::FusedAppendInsert => {
+                if !storage_cursor_ids.contains(&op.p1) {
+                    return true;
+                }
+            }
+            _ => {}
+        }
+    }
+
+    false
